    for field in ['Matn','hadithTxt']:
        t = h.get(field)
        if not t: 
            continue
        norm = normalize_arabic(t)
        # compute similarity with "window" size equal to length of target; best sliding window approximate:
        # We'll compute similarity of target against each sentence maybe; but for speed, just compute direct ratio on entire string which is large may drop ratio.
        # Let's compute LCS ratio using SequenceMatcher; to approximate, take the max across substrings around the occurrences of key tokens "بعث".
        if 'بعث' in norm:
            s = sim(target_norm, norm)
            if s > 0.3:
                best.append((s, h['hadithID'], h['BookID'], h['title'], field, t[:300]))
